static inline int csilc_enc_TranscodeCodec(csilc_buf *b, const TranscodeCodec *v);
static inline int csilc_dec_TranscodeCodec(const csilc_value *src, CsilCodecArena *a, TranscodeCodec *out);
static inline int csilc_enc_StreamPref(csilc_buf *b, const StreamPref *v);
